/**
 * MtgBroker logo — embedded as base64 data URI.
 * This eliminates all possible failure modes: no network request,
 * no CORS, no CDN, no static file serving, no path resolution.
 */
const LOGO_BASE64 = "data:image/png;base64,";

export default function Logo({ height = 28, inverted = false }) {
  const w = Math.round(height * 6.29);
  return (
    <img
      src={LOGO_BASE64}
      alt="MtgBroker"
      width={w}
      height={height}
      style={{
        height: `${height}px`,
        width: `${w}px`,
        maxWidth: "none",
        display: "block",
        objectFit: "contain",
        ...(inverted ? { filter: "brightness(0) invert(1)" } : {}),
      }}
    />
  );
}
